body:
This issue is an extension of #4858 . The repository is https://github.com/Karl-Han/cvw/

## Issue Description

There are two versions of testbench code (both of them are equivalent):

- posedge clk version: `if(Validate)` block is put inside an `always @(posedge clk)` block. 
    - on `posedge_clk` branch with `git checkout 73119e3`
- posedge Validate version: `if(Validate)` block is put into another `always @(posedge Validate)` block
    - on `posedge_validate` branch with `git checkout 724483b9`

These two version have with the following difference (the complete code block is attached below):
> git diff posedge_clk posedge_validate

```diff
diff --git a/testbench/testbench.sv b/testbench/testbench.sv
index 7c6cc42ea..61c6ecc4f 100644
--- a/testbench/testbench.sv
+++ b/testbench/testbench.sv
@@ -327,6 +327,9 @@ module testbench;
         $display("Benchmark: coremark is done.");
         $stop;
       end
+  end
+
+  always @(posedge Validate) begin
     if(Validate) begin
       count_validate = count_validate +1;
       if (TEST == "embench") begin
```

In simple words, posedge clk version includes everything inside the `always @(posedge clk)`, while posedge validate version separate the if(Validate) part and put it into `always @(posedge Validate)` block.

The code inside if(Validate) is mostly system calls and file read write.

## Expectation and Runtime Comparison

The expectation was that posedge clk version, while increasing the number of checks performed due to its placement in a clocked process, would not significantly impact overall performance as it is executed the same amount of time as the posedge validate version.

However, the results of posedge validate version have shown a substantial increase in running time, contrary to our expectations. Below are the measured times before and after the modification, in two different modes of operation (more than 40% time difference) :

| mode | posedge clk(s) | posedge Validate(s) |
| --- | --- | --- |
| profiling mode | 1431.83 | 924 |
| non-profile mode | 521.55 | 71.88 |

And the number of validate code block execution is the same for both cases:

posedge clk version in non-profiling mode:
```shell
SUCCESS! All tests ran without failures.
validate =         50
count_clk = testbenchd              445364
- ../testbench/testbench.sv:369: Verilog $finish
501.41user 0.12system 8:21.55elapsed 99%CPU (0avgtext+0avgdata 328960maxresident)k
0inputs+0outputs (0major+80854minor)pagefaults 0swaps
```

posedge validate version in non-profiling mode:
```shell
rv64i_m/I/src/xori-01.S succeeded.  Brilliant!!!
SUCCESS! All tests ran without failures.
validate =         50
count_clk = testbenchd              445363
- ../testbench/testbench.sv:372: Verilog $finish
71.75user 0.13system 1:11.88elapsed 99%CPU (0avgtext+0avgdata 328960maxresident)k
0inputs+0outputs (0major+80823minor)pagefaults 0swaps
```

## Verilator Information

Version: Verilator 5.021 devel rev v5.020-16-g7507c5f56
OS Version: Linux 6.5.0-25-generic 25~22.04.1-Ubuntu
Command: 
```shell
# for non-profiling mode
time verilator -GTEST="\"arch64i\"" -O3 -DVERILATOR=1 --no-trace-top \
	--timescale "1ns/1ns" --timing --binary --top-module testbench \
	"-I../config/shared" "-I../config/rv64gc" ../src/cvw.sv ../testbench/testbench.sv ../testbench/common/*.sv ../src/*/*.sv ../src/*/*/*.sv --relative-includes

# for profiling mode
time verilator -GTEST="\"arch64i\"" --prof-cfuncs -O3 -DVERILATOR=1 --no-trace-top \
	--timescale "1ns/1ns" --timing --binary --top-module testbench \
	"-I../config/shared" "-I../config/rv64gc" ../src/cvw.sv ../testbench/testbench.sv ../testbench/common/*.sv ../src/*/*.sv ../src/*/*/*.sv --relative-includes
```

## Appendix
```systemverilog
  always @(posedge clk) begin
    count_clk = count_clk+1;
    if(SelectTest) begin
      if (riscofTest) memfilename = {pathname, tests[test], "/ref/ref.elf.memfile"};
      else if(TEST == "buildroot") begin 
        memfilename = {RISCV_DIR, "/linux-testvectors/ram.bin"};
        bootmemfilename = {RISCV_DIR, "/linux-testvectors/bootmem.bin"};
      end
      else            memfilename = {pathname, tests[test], ".elf.memfile"};
      if (riscofTest) begin
        ProgramAddrMapFile = {pathname, tests[test], "/ref/ref.elf.objdump.addr"};
        ProgramLabelMapFile = {pathname, tests[test], "/ref/ref.elf.objdump.lab"};
      end else if (TEST == "buildroot") begin
        ProgramAddrMapFile = {RISCV_DIR, "/buildroot/output/images/disassembly/vmlinux.objdump.addr"};
        ProgramLabelMapFile = {RISCV_DIR, "/buildroot/output/images/disassembly/vmlinux.objdump.lab"};
      end else begin
        ProgramAddrMapFile = {pathname, tests[test], ".elf.objdump.addr"};
        ProgramLabelMapFile = {pathname, tests[test], ".elf.objdump.lab"};
      end
      // declare memory labels that interest us, the updateProgramAddrLabelArray task will find 
      // the addr of each label and fill the array. To expand, add more elements to this array 
      // and initialize them to zero (also initilaize them to zero at the start of the next test)
      updateProgramAddrLabelArray(ProgramAddrMapFile, ProgramLabelMapFile, ProgramAddrLabelArray);
    end
    
  ////////////////////////////////////////////////////////////////////////////////
  // Verify the test ran correctly by checking the memory against a known signature.
  ////////////////////////////////////////////////////////////////////////////////
    if(TestBenchReset) test = 1;
    if (TEST == "coremark")
      if (dut.core.priv.priv.EcallFaultM) begin
        $display("Benchmark: coremark is done.");
        $stop;
      end
    if(Validate) begin
      count_validate = count_validate +1;
      if (TEST == "embench") begin
        // Writes contents of begin_signature to .sim.output file
        // this contains instret and cycles for start and end of test run, used by embench 
        // python speed script to calculate embench speed score. 
        // also, begin_signature contains the results of the self checking mechanism, 
        // which will be read by the python script for error checking
        $display("Embench Benchmark: %s is done.", tests[test]);
        if (riscofTest) outputfile = {pathname, tests[test], "/ref/ref.sim.output"};
        else outputfile = {pathname, tests[test], ".sim.output"};
        outputFilePointer = $fopen(outputfile, "w");
        i = 0;
        testadr = ($unsigned(begin_signature_addr))/(P.XLEN/8);
        while ($unsigned(i) < $unsigned(5'd5)) begin
          $fdisplayh(outputFilePointer, DCacheFlushFSM.ShadowRAM[testadr+i]);
          i = i + 1;
        end
        $fclose(outputFilePointer);
        $display("Embench Benchmark: created output file: %s", outputfile);
      end else if (TEST == "coverage64gc") begin
        $display("Coverage tests don't get checked");
      end else begin 
        // for tests with no self checking mechanism, read .signature.output file and compare to check for errors
        // clear signature to prevent contamination from previous tests
        if (!begin_signature_addr)
          $display("begin_signature addr not found in %s", ProgramLabelMapFile);
        else if (TEST != "embench") begin   // *** quick hack for embench.  need a better long term solution
          CheckSignature(pathname, tests[test], riscofTest, begin_signature_addr, errors);
          if(errors > 0) totalerrors = totalerrors + 1;
        end
      end
      test = test + 1; // *** this probably needs to be moved.
      if (test == tests.size()) begin
        if (totalerrors == 0) $display("SUCCESS! All tests ran without failures.");
        else $display("FAIL: %d test programs had errors", totalerrors);
        $display("validate = %d", count_validate);
        $display("count_clk = %ld", count_clk);
`ifdef verilator
        $finish;
`else
        $stop; // if this is changed to $finish, wally-batch.do does not go to the next step to run coverage
`endif
      end
    end
  end
```
